421: 		 * convert 1 to 0 ("all the tuples") and 0 to a very small fraction.
422: 		 */
423: 		if (tuple_fraction >= 1.0)
424: 			tuple_fraction = 0.0;
425: 		else if (tuple_fraction <= 0.0)
